def extract_tar_file(tar_file_path: str, destination_dir: str) -> None:
    """
    Extracts a tar file to a specified destination directory securely.

    Args:
        tar_file_path: Path to the tar file to extract.
        destination_dir: Path to the directory where contents will be extracted.

    Raises:
        FileNotFoundError: If the tar file or destination directory does not exist.
        ValueError: If the file path contains invalid characters or is not a valid tar file.
        subprocess.CalledProcessError: If the tar extraction command fails.
    """
    # Validate that the tar file exists
    if not os.path.isfile(tar_file_path):
        raise FileNotFoundError(f"Tar file not found: {tar_file_path}")

    # Validate that the destination directory exists
    if not os.path.isdir(destination_dir):
        raise FileNotFoundError(f"Destination directory not found: {destination_dir}")

    # Resolve to absolute paths to prevent path traversal
    tar_file_path = os.path.realpath(tar_file_path)
    destination_dir = os.path.realpath(destination_dir)

    # Validate the tar file has a recognized tar extension
    allowed_extensions = ('.tar', '.tar.gz', '.tgz', '.tar.bz2', '.tbz2', '.tar.xz', '.txz')
    if not any(tar_file_path.lower().endswith(ext) for ext in allowed_extensions):
        raise ValueError(
            f"File does not have a recognized tar extension. "
            f"Allowed extensions: {allowed_extensions}"
        )

    # Validate paths don't contain null bytes or other dangerous characters
    for path in [tar_file_path, destination_dir]:
        if '\x00' in path:
            raise ValueError("Path contains null bytes")

    # Determine the appropriate decompression flag based on file extension
    lower_path = tar_file_path.lower()
    if lower_path.endswith(('.tar.gz', '.tgz')):
        decompress_flag = '-z'
    elif lower_path.endswith(('.tar.bz2', '.tbz2')):
        decompress_flag = '-j'
    elif lower_path.endswith(('.tar.xz', '.txz')):
        decompress_flag = '-J'
    elif lower_path.endswith('.tar'):
        decompress_flag = None
    else:
        raise ValueError("Unrecognized tar file format")

    # Build the command as a fixed argument array (no shell=True)
    cmd = ['/usr/bin/tar']

    if decompress_flag:
        cmd.append(decompress_flag)

    cmd.extend([
        '-xf',
        tar_file_path,
        '-C',
        destination_dir,
    ])

    # Execute the command securely with shell=False (the default, but explicit)
    subprocess.run(
        cmd,
        check=True,
        shell=False,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
    )


def list_tar_contents(tar_file_path: str) -> list:
    """
    Lists the contents of a tar file without extracting, for inspection purposes.

    Args:
        tar_file_path: Path to the tar file.

    Returns:
        A list of file paths contained in the tar archive.
    """
    if not os.path.isfile(tar_file_path):
        raise FileNotFoundError(f"Tar file not found: {tar_file_path}")

    tar_file_path = os.path.realpath(tar_file_path)

    allowed_extensions = ('.tar', '.tar.gz', '.tgz', '.tar.bz2', '.tbz2', '.tar.xz', '.txz')
    if not any(tar_file_path.lower().endswith(ext) for ext in allowed_extensions):
        raise ValueError(f"File does not have a recognized tar extension.")

    if '\x00' in tar_file_path:
        raise ValueError("Path contains null bytes")

    lower_path = tar_file_path.lower()
    if lower_path.endswith(('.tar.gz', '.tgz')):
        decompress_flag = '-z'
    elif lower_path.endswith(('.tar.bz2', '.tbz2')):
        decompress_flag = '-j'
    elif lower_path.endswith(('.tar.xz', '.txz')):
        decompress_flag = '-J'
    elif lower_path.endswith('.tar'):
        decompress_flag = None
    else:
        raise ValueError("Unrecognized tar file format")

    cmd = ['/usr/bin/tar']
    if decompress_flag:
        cmd.append(decompress_flag)
    cmd.extend(['-tf', tar_file_path])

    result = subprocess.run(
        cmd,
        check=True,
        shell=False,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
    )

    return [line for line in result.stdout.strip().split('\n') if line]


